const allItems = $input.all().map(i => i.json);
const context = { priorities: [], signals: [], meetings: [], emails: [], blockers: [] };
for (const item of allItems) {
  if (item.source && context[item.source] !== undefined) context[item.source] = item.items || [];
}

const matrix = context.priorities.map(p => {
  const relatedSignals = context.signals.filter(s => {
    const pTitle = (p.title || '').toLowerCase();
    const sTitle = (s.title || '').toLowerCase();
    return pTitle.split(' ').some(w => w.length > 3 && sTitle.includes(w));
  });
  const relatedEmails = context.emails.filter(e => {
    const pTitle = (p.title || '').toLowerCase();
    const eSubject = (e.subject || '').toLowerCase();
    return pTitle.split(' ').some(w => w.length > 3 && eSubject.includes(w));
  });
  const relatedBlockers = context.blockers.filter(b => {
    const pTitle = (p.title || '').toLowerCase();
    const bTitle = (b.title || '').toLowerCase();
    return pTitle.split(' ').some(w => w.length > 3 && bTitle.includes(w));
  });
  return { ...p, relatedSignals, relatedEmails, relatedBlockers, signalCount: relatedSignals.length, emailCount: relatedEmails.length, blockerCount: relatedBlockers.length };
});

return [{ json: { matrix, meetings: context.meetings, totalPriorities: context.priorities.length, totalSignals: context.signals.length, totalBlockers: context.blockers.length } }];

const content = $json.message?.content || '';
let parsed;
try { const m = content.match(/\{[\s\S]*\}/); parsed = m ? JSON.parse(m[0]) : { impactScores: [] }; } catch(e) { parsed = { impactScores: [] }; }
return [{ json: { impactScores: parsed.impactScores || parsed } }];

const content = $json.message?.content || '';
let parsed;
try { const m = content.match(/\{[\s\S]*\}/); parsed = m ? JSON.parse(m[0]) : { urgencyScores: [] }; } catch(e) { parsed = { urgencyScores: [] }; }
return [{ json: { urgencyScores: parsed.urgencyScores || parsed } }];

const content = $json.message?.content || '';
let parsed;
try { const m = content.match(/\{[\s\S]*\}/); parsed = m ? JSON.parse(m[0]) : { ranking: [] }; } catch(e) { parsed = { ranking: [] }; }
return [{ json: { newRanking: parsed.ranking || [] } }];

const ranking = $json.newRanking || [];
let summary = ':arrows_counterclockwise: *Priority Re-Ranking Update*\n\n';
summary += `_${new Date().toISOString().split('T')[0]} ${new Date().toTimeString().split(' ')[0]}_\n\n`;
summary += '*New Priority Order:*\n';
ranking.forEach(r => {
  const arrow = r.change === 'up' ? ':arrow_up:' : r.change === 'down' ? ':arrow_down:' : ':white_circle:';
  summary += `${r.rank}. ${arrow} *${r.title}* (Score: ${r.finalScore}) - ${r.rationale || ''}\n`;
});
summary += `\n_${ranking.filter(r => r.change !== 'same').length} priorities changed position_`;
return [{ json: { ...($json), changeSummary: summary, changedCount: ranking.filter(r => r.change !== 'same').length } }];

const ranking = $json.newRanking || [];
let text = ':arrows_counterclockwise: *Priority Ranking Updated*\n\n';
ranking.slice(0, 5).forEach(r => {
  const arrow = r.change === 'up' ? ':arrow_up:' : r.change === 'down' ? ':arrow_down:' : ':white_circle:';
  text += `${r.rank}. ${arrow} ${r.title} (${r.finalScore})\n`;
});
return [{ json: { slackText: text } }];
